#include<bits/stdc++.h>
using namespace std;
int main() {
	string a;
	unsigned long long int c;
	long long n, m;
	cin >> n;
	queue<unsigned long long int> b;
	for (long long i = 0; i < n; i++) {
		cin >> a;
		if (a == "1") {
			cin >> c;
			b.push(c);
		} else if (a == "2") {
			if (b.empty()) {
				cout << "ERR_CANNOT_POP" << endl;
			} else {
				b.pop();
			}
		} else if (a == "3") {
			if (b.empty()) {
				cout << "ERR_CANNOT_QUERY" << endl;
			} else {
				cout << b.front() << endl;
			}
		} else if (a == "4") {
			cout << b.size() << endl;
		}
	}

	return 0;
}
